{
  "title": "स्टोरेज लागत विश्लेषण",
  "group": "लागत अनुकूलन",
  "options": [
    {
      "text": "सभी डेटा के लिए S3 Standard"
    },
    {
      "text": "हमेशा सबसे सस्ते स्टोरेज का उपयोग करें"
    },
    {
      "text": "एक्सेस पैटर्न के आधार पर स्टोरेज क्लासेस को मिक्स करें"
    },
    {
      "text": "सब कुछ Glacier में स्टोर करें"
    }
  ],
  "questionProse": [
    "1PB डेटा को स्टोर करते वक्त सबसे स्मार्ट (और सस्ता) तरीका कौन सा है, जबकि 20% डेटा रोज़, 30% महीने में और 50% साल में ही एक्सेस होता है?"
  ],
  "explanationProse": [
    "इष्टतम स्टोरेज रणनीति:\n  - दैनिक एक्सेस के लिए 20% डेटा S3 Standard में\n  - मासिक एक्सेस के लिए 30% डेटा S3 Standard-IA में\n  - वार्षिक एक्सेस के लिए 50% डेटा Glacier में\n\n  यह रणनीति इसलिए काम करती है क्योंकि यह आपके एक्सेस पैटर्न के हिसाब से स्टोरेज को बाँट देती है, जिससे बिना परफॉर्मेंस खोए लागत काफी कम हो जाती है।\n\n  लागत का सही अनुमान लगाने के लिए इन बातों पर गौर करें:\n  - प्रति GB स्टोरेज प्राइसिंग\n  - रिट्रीवल (पुनर्प्राप्ति) लागत\n  - एक्सेस पैटर्न\n  - ट्रांज़िशन (स्थानांतरण) लागत"
  ]
}
